import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classic() {
        int[] nums = {2, 0, 1, 2, 1, 0};
        new Solution().sortColors(nums);
        assertArrayEquals(new int[]{0, 0, 1, 1, 2, 2}, nums);
    }

    @Test
    void empty() {
        int[] nums = {};
        new Solution().sortColors(nums);
        assertArrayEquals(new int[]{}, nums);
    }

    @Test
    void singleElement() {
        int[] nums = {1};
        new Solution().sortColors(nums);
        assertArrayEquals(new int[]{1}, nums);
    }

    @Test
    void allZeros() {
        int[] nums = {0, 0, 0};
        new Solution().sortColors(nums);
        assertArrayEquals(new int[]{0, 0, 0}, nums);
    }

    @Test
    void allTwos() {
        int[] nums = {2, 2, 2};
        new Solution().sortColors(nums);
        assertArrayEquals(new int[]{2, 2, 2}, nums);
    }

    @Test
    void alreadySorted() {
        int[] nums = {0, 0, 1, 2, 2};
        new Solution().sortColors(nums);
        assertArrayEquals(new int[]{0, 0, 1, 2, 2}, nums);
    }

    @Test
    void onlyZerosAndTwos() {
        // no 1s — bucket[1] == 0; write-back must skip it cleanly
        int[] nums = {2, 0, 2, 0};
        new Solution().sortColors(nums);
        assertArrayEquals(new int[]{0, 0, 2, 2}, nums);
    }
}
